import { notFound } from "next/navigation";
import { prisma } from "../../../lib/prisma";
import CarDetailClient from "./car-detail-client";
import { CAR_GALLERY_ENTRIES } from "./gallery-routes";

export default async function CarDetailPage({
  params,
}: {
  params: Promise<{ slug: string }>;
}) {
  const { slug } = await params;
  const model = await prisma.carModel.findUnique({
    where: { slug },
    include: {
      variants: {
        orderBy: { sortOrder: "asc" },
        include: {
          specs: { orderBy: [{ group: "asc" }, { sortOrder: "asc" }] },
          price: true,
          colors: true,
        },
      },
      colors: true,
      images: {
        include: { contents: true },
      },
    },
  });

  if (!model) notFound();

  const detailBanners = await prisma.carDetailBanner.findMany({
    where: { carModelId: model.id },
  });

  const bannerImages = model.images
    .filter((img) => img.type === "BANNER")
    .map((img) => ({ url: img.url }));

  const carouselImages = model.images
    .filter((img) => img.type === "CAROUSEL")
    .map((img) => ({
      url: img.url,
      title: img.contents?.title ?? null,
      content: img.contents?.content ?? null,
    }));

  const interiorImages = model.images
    .filter((img) => img.type === "INTERIOR")
    .map((img) => ({
      url: img.url,
      title: img.contents?.title ?? null,
      content: img.contents?.content ?? null,
    }));

  const eksteriorImages = model.images
    .filter((img) => img.type === "EKSTERIOR")
    .map((img) => ({
      url: img.url,
      title: img.contents?.title ?? null,
      content: img.contents?.content ?? null,
    }));

  const previewImages = model.images
    .filter((img) => img.type === "PREVIEW")
    .map((img) => ({ url: img.url }));

  // Build unique color list per variant with preview image
  const colorImageMap = new Map(
    previewImages.map((img) => {
      // Extract color code from filename like /images/fronx/preview/ZYZ-color.webp
      const filename = img.url.split("/").pop() ?? "";
      const code = filename.replace("-color.webp", "").replace(".webp", "");
      return [code, img.url];
    }),
  );

  // Build compare variants (top 3 by sort order)
  const compareVariants = model.variants.slice(0, 3).map((v) => {
    const variantColors = model.colors
      .filter((c) => c.carVariantCode === v.code)
      .map((c) => ({
        code: c.colorCode,
        imageUrl: colorImageMap.get(c.colorCode) ?? null,
      }));

    return {
      id: v.id,
      code: v.code,
      name: v.name ?? v.code,
      price: v.price?.otrPrice ? Number(v.price.otrPrice) : 0,
      colors: variantColors,
    };
  });

  // All variants for pricing section
  const allVariants = model.variants.map((v) => ({
    id: v.id,
    code: v.code,
    name: v.name ?? v.code,
    price: v.price?.otrPrice ? Number(v.price.otrPrice) : 0,
  }));

  // Spec comparison: features & performance
  const specVariants = model.variants.slice(0, 3);
  const performanceSpecs: { key: string; values: string[] }[] = [];
  const featureSpecs: { key: string; values: string[] }[] = [];

  const performanceKeys = Array.from(
    new Set(
      specVariants.flatMap((v) =>
        v.specs
          .filter((s) => s.group.toUpperCase() === "PERFORMANCE")
          .map((s) => s.key.trim()),
      ),
    ),
  );

  const featureKeys = Array.from(
    new Set(
      specVariants.flatMap((v) =>
        v.specs
          .filter((s) => s.group.toUpperCase() === "FEATURES")
          .map((s) => s.key.trim()),
      ),
    ),
  );

  const specMap = new Map<string, string>();
  for (const v of specVariants) {
    for (const s of v.specs) {
      specMap.set(`${v.id}::${s.key.trim()}`, s.value);
    }
  }

  for (const key of performanceKeys) {
    performanceSpecs.push({
      key,
      values: specVariants.map((v) => specMap.get(`${v.id}::${key}`) ?? "-"),
    });
  }

  for (const key of featureKeys) {
    featureSpecs.push({
      key,
      values: specVariants.map((v) => specMap.get(`${v.id}::${key}`) ?? "-"),
    });
  }

  return (
    <CarDetailClient
      model={{
        slug: model.slug,
        name: model.name,
        category: model.category,
      }}
      bannerImages={bannerImages}
      carouselImages={carouselImages}
      interiorImages={interiorImages}
      eksteriorImages={eksteriorImages}
      compareVariants={compareVariants}
      specVariantHeaders={specVariants.map((v) => v.name ?? v.code)}
      performanceSpecs={performanceSpecs}
      featureSpecs={featureSpecs}
      allVariants={allVariants}
      detailBanners={detailBanners}
    />
  );
}
